/// <summary>
/// Extension of the <c>CustConfirmTrans</c> table for the ETGSPAIN model.
/// </summary>
[ExtensionOf(tableStr(CustConfirmTrans))]
final class CustConfirmTransETGSPAIN_Extension
{
}

Method.Source:
/// <summary>
/// Extension of the <c>initFromSalesLine</c> method.
/// </summary>
/// <param name="_salesLine">SalesLine record</param>
void initFromSalesLine(SalesLine _salesLine)
{
    next initFromSalesLine(_salesLine);

    // Puerto descarga y Carga
    if(CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        this.ETGSPAINPurchUnloadPortId           = _salesLine.ETGSPAINPurchUnloadPortId;
        this.ETGSPAINPurchLoadPortId             = _salesLine.ETGSPAINPurchLoadPortId;
        this.ETGSPAINAppliedInventLocation       = _salesLine.ETGSPAINdisplayAppliedInventLocation();
        this.ETGSPAINAppliedInventLocationName   = InventLocation::find(this.ETGSPAINAppliedInventLocation).Name;
    }
}
